import{_ as e,c as t,o,a4 as a}from"./chunks/framework.ttppV29E.js";const f=JSON.parse('{"title":"Repositories","description":"","frontmatter":{},"headers":[],"relativePath":"docs/getting-started/repositories.md","filePath":"docs/getting-started/repositories.md","lastUpdated":1780482697000}'),n={name:"docs/getting-started/repositories.md"},i=a(`<h1 id="repositories" tabindex="-1">Repositories <a class="header-anchor" href="#repositories" aria-label="Permalink to &quot;Repositories&quot;">​</a></h1><p>Repositories provide a way for you to use your own storage for saving endpoints. This allows for you to handle your own backups, imports, version control, etc right from your favourite Git provider. Some examples of Git providers are <a href="https://github.com" target="_blank" rel="noreferrer">GitHub</a>, <a href="https://bitbucket.org" target="_blank" rel="noreferrer">Bitbucket</a>, and <a href="https://about.gitlab.com/" target="_blank" rel="noreferrer">GitLab</a>, although there are many more, including self-hosted options.</p><h2 id="adding-a-repository" tabindex="-1">Adding a repository <a class="header-anchor" href="#adding-a-repository" aria-label="Permalink to &quot;Adding a repository&quot;">​</a></h2><p>To add a repository you will need to know your repository URL (you can find this out from your provider), and any credentials needed to read from it. You should also ensure that this repository contains a valid AireGlu file structure (see Repository Layout below).</p><ul><li>Go to the Repositories section, and click the <code>+</code> button at the top right corner of the page</li><li>Choose your authentication method (see below for more information on each)</li><li>Enter the repository URL (starting with <code>https://</code> or <code>git@</code>, depending on if you&#39;re using SSH authentication)</li><li>Select the repository branch (will default to master if not specified)</li><li>If you are using auto sync and want to be notified of any problems, enter your email address in <code>Error email</code></li><li>If you want to automatically pull in changes that you make in git, check the <code>Auto Sync Repository</code> option. If you want to do this manually, make sure this option is not ticked.</li><li>If you are using authentication then enter the appropriate details (see below)</li><li>Click <code>Test and Save</code> to verify AireGlu can connect to your repository</li></ul><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><p>It is likely, and reccomended, that your repository requires some form of authentication before it can be used. There are 3 options available to you for this. None, Credentials, and SSH.</p><h4 id="none" tabindex="-1">None <a class="header-anchor" href="#none" aria-label="Permalink to &quot;None&quot;">​</a></h4><p>While not recommended, you may use a repository that does not require any authentication and is publicly readable and writable. There is nothing extra to configure here, but be aware that anyone will be able to see or change your endpoints if they find your repository.</p><h4 id="credentials" tabindex="-1">Credentials <a class="header-anchor" href="#credentials" aria-label="Permalink to &quot;Credentials&quot;">​</a></h4><p>Credentials allows for the use of a username and password to login to the repository. AireGlu will act as the user whose credentials have been used, and will appear on the commit history as that user.</p><h4 id="ssh" tabindex="-1">SSH <a class="header-anchor" href="#ssh" aria-label="Permalink to &quot;SSH&quot;">​</a></h4><p>Finally authentication can be completed with the use of a public and private key pair, using SSH. This is the most complex to set up, as it requires generating a key pair, adding the public key to your Git repository, and the private key to AireGlu. It is reccomended to ensure this private key is not used anywhere else for security reasons. The benefit of this approach is that each device that uses SSH to connect can have its own key that can be revoked if it gets compromised, without affecting any of the other devices.</p><p>When using SSH authentication, your repository url should begin with <code>git@</code> or something similar. It should not start with <code>https://</code>.</p><p><a href="https://docs.github.com/en/github/authenticating-to-github/adding-a-new-ssh-key-to-your-github-account" target="_blank" rel="noreferrer">GitHub</a> and <a href="https://support.atlassian.com/bitbucket-cloud/docs/set-up-an-ssh-key/" target="_blank" rel="noreferrer">Bitbucket</a> both have guides on how to set up a key for your account as examples, but most providers support this feature, and will offer some support in setting it up.</p><h2 id="repository-layout" tabindex="-1">Repository Layout <a class="header-anchor" href="#repository-layout" aria-label="Permalink to &quot;Repository Layout&quot;">​</a></h2><p>Use the flat JSON layout for new repositories. Existing repositories using the folder-per-entity layout continue to work without changes.</p><h3 id="flat-layout-recommended" tabindex="-1">Flat layout (recommended) <a class="header-anchor" href="#flat-layout-recommended" aria-label="Permalink to &quot;Flat layout (recommended)&quot;">​</a></h3><p>Each endpoint or MCP server config is a single <code>.json</code> file directly under the parent folder. AireGlu reads the entity name from the file contents; name the file after the entity it contains.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>repo-root/</span></span>
<span class="line"><span>├── Endpoints/</span></span>
<span class="line"><span>│   ├── MyEndpoint.json</span></span>
<span class="line"><span>│   └── Another.json</span></span>
<span class="line"><span>└── McpServers/</span></span>
<span class="line"><span>    ├── my-server.json</span></span>
<span class="line"><span>    └── another.json</span></span></code></pre></div><p>Other files in the folder (for example <code>README.md</code>) are ignored.</p><h3 id="flat-layout-with-aireglu-parent" tabindex="-1">Flat layout with <code>AireGlu/</code> parent <a class="header-anchor" href="#flat-layout-with-aireglu-parent" aria-label="Permalink to &quot;Flat layout with \`AireGlu/\` parent&quot;">​</a></h3><p>Use this when the repository contains other products or folders. AireGlu detects the <code>AireGlu/</code> folder automatically and scans from there; root-level <code>Endpoints/</code> and <code>McpServers/</code> are ignored when <code>AireGlu/</code> is present.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>repo-root/</span></span>
<span class="line"><span>├── AireGlu/</span></span>
<span class="line"><span>│   ├── Endpoints/</span></span>
<span class="line"><span>│   │   ├── MyEndpoint.json</span></span>
<span class="line"><span>│   │   └── Another.json</span></span>
<span class="line"><span>│   └── McpServers/</span></span>
<span class="line"><span>│       └── my-server.json</span></span>
<span class="line"><span>├── Forms/                        ← other products coexist at root</span></span>
<span class="line"><span>└── Flow/</span></span></code></pre></div><h3 id="folder-per-entity-layout-legacy" tabindex="-1">Folder-per-entity layout (legacy) <a class="header-anchor" href="#folder-per-entity-layout-legacy" aria-label="Permalink to &quot;Folder-per-entity layout (legacy)&quot;">​</a></h3><p>Still supported for existing repositories. Each entity lives in its own subfolder with a fixed-name config file inside. Endpoint configs may be <code>endpoint.json</code>, <code>endpoint.yml</code>, or <code>endpoint.yaml</code>; MCP server configs must be <code>mcp-server.json</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>repo-root/</span></span>
<span class="line"><span>├── Endpoints/                    required</span></span>
<span class="line"><span>│   └── MyEndpoint/</span></span>
<span class="line"><span>│       └── endpoint.json         (or endpoint.yml / endpoint.yaml)</span></span>
<span class="line"><span>└── McpServers/                   optional</span></span>
<span class="line"><span>    └── MyServer/</span></span>
<span class="line"><span>        └── mcp-server.json</span></span></code></pre></div><h3 id="exporting-an-endpoint-config" tabindex="-1">Exporting an Endpoint Config <a class="header-anchor" href="#exporting-an-endpoint-config" aria-label="Permalink to &quot;Exporting an Endpoint Config&quot;">​</a></h3><p>To export an endpoint for saving to git:</p><ul><li>Go to the Endpoints page in AireGlu</li><li>Click the export button (box with an arrow icon) on the endpoint overview</li><li>Choose JSON format</li><li>If you are using any password/secrets fields and you want the password or secret reference preserved on re-import, choose <code>Include encrypted values</code>; otherwise placeholders are written and must be replaced before the endpoint will run.</li><li>Save the export as a plain-text <code>.json</code> file<div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Use Notepad or a plain-text editor. Word or other rich-text editors will corrupt the file.</p></div></li><li>Place the file in your repository matching the layout above.</li></ul><h3 id="exporting-an-mcp-server-config" tabindex="-1">Exporting an MCP Server Config <a class="header-anchor" href="#exporting-an-mcp-server-config" aria-label="Permalink to &quot;Exporting an MCP Server Config&quot;">​</a></h3><p>To export an MCP server config for saving to git:</p><ul><li>Go to <strong>AI Tools &gt; MCP Servers</strong></li><li>Click the three-dot menu on the server and select <strong>Export</strong> — the full configuration is copied to your clipboard as JSON</li><li>Paste the clipboard contents into a plain-text <code>.json</code> file<div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Use Notepad or a plain-text editor. Word or other rich-text editors will corrupt the file.</p></div></li><li>Place the file in your repository matching the layout above.</li></ul>`,33),s=[i];function r(l,p,d,c,h,u){return o(),t("div",null,s)}const g=e(n,[["render",r]]);export{f as __pageData,g as default};
